import { readFileSync, writeFileSync, mkdirSync, existsSync, statSync } from "node:fs";
import path from "node:path";
import { execFileSync } from "node:child_process";

const ROOT = process.cwd();
const ENTRY_TS = "src/ts/main.ts";
const ENTRY_JS = ENTRY_TS.replace(/\.ts$/, ".js");
const TEMPLATE = "mikuscore-src.html";
const DIST = "mikuscore.html";
const SAMPLE1_MXL_PATH = "src/samples/musicxml/sample1.mxl";
const SAMPLE2_MXL_PATH = "src/samples/musicxml/sample2.mxl";
const SAMPLE3_MXL_PATH = "src/samples/musicxml/sample3.mxl";
const SAMPLE4_MXL_PATH = "src/samples/musicxml/sample4.mxl";
const SAMPLE6_XML_PATH = "src/samples/musicxml/sample6.musicxml";
const SAMPLE7_XML_PATH = "src/samples/musicxml/sample7.musicxml";
const SAMPLE1_TS_PATH = "src/ts/sampleXml1.ts";
const SAMPLE2_TS_PATH = "src/ts/sampleXml2.ts";
const SAMPLE3_TS_PATH = "src/ts/sampleXml3.ts";
const SAMPLE4_TS_PATH = "src/ts/sampleXml4.ts";
const SAMPLE6_TS_PATH = "src/ts/sampleXml6.ts";
const SAMPLE7_TS_PATH = "src/ts/sampleXml7.ts";
const TOKEN_CSS_PATH = "src/css/md3/token-spec.css";
const CORE_CSS_PATH = "src/css/md3/core-spec.css";
const CSS_PATH = "src/css/app.css";
const VEROVIO_JS_PATH = "src/js/verovio.js";
const MIDI_WRITER_JS_PATH = "src/js/midi-writer.js";
const UF3P_MIKUSCORE_IIFE_JS_PATH = "src/vendor/utaformatix3/utaformatix3-ts-plus.mikuscore.iife.js";
const JS_OUT = "src/js/main.js";
const TMP_DIR = ".mikuscore-build";
const TMP_TSBUILDINFO = `${TMP_DIR}/build.tsbuildinfo`;

const normalize = (p) => p.split(path.sep).join("/");
const toAbs = (relPath) => path.join(ROOT, relPath);
const readText = (relPath) => readFileSync(toAbs(relPath), "utf8");
const getMtimeMs = (relPath) => {
  const abs = toAbs(relPath);
  if (!existsSync(abs)) return null;
  return statSync(abs).mtimeMs;
};
const isGeneratedFileCurrent = (sourceRelPath, generatedRelPath) => {
  const sourceMtime = getMtimeMs(sourceRelPath);
  const generatedMtime = getMtimeMs(generatedRelPath);
  if (sourceMtime == null || generatedMtime == null) return false;
  return generatedMtime >= sourceMtime;
};
const writeTextIfChanged = (relPath, text) => {
  const abs = toAbs(relPath);
  if (existsSync(abs)) {
    const current = readFileSync(abs, "utf8");
    if (current === text) return false;
  }
  writeFileSync(abs, text, "utf8");
  return true;
};

const extractMusicXmlTextFromMxl = (mxlPath) => {
  const abs = toAbs(mxlPath);
  const containerXml = execFileSync("unzip", ["-p", abs, "META-INF/container.xml"], { encoding: "utf8" });
  const rootfileMatch = containerXml.match(/full-path="([^"]+)"/i);
  if (!rootfileMatch?.[1]) {
    throw new Error(`Failed to locate rootfile path in ${mxlPath}`);
  }
  const rootfilePath = rootfileMatch[1];
  const xml = execFileSync("unzip", ["-p", abs, rootfilePath], { encoding: "utf8" });
  return xml.replace(/\r\n/g, "\n");
};

const syncBuiltInSamples = () => {
  if (existsSync(toAbs(SAMPLE1_MXL_PATH))) {
    if (!isGeneratedFileCurrent(SAMPLE1_MXL_PATH, SAMPLE1_TS_PATH)) {
      const xml = extractMusicXmlTextFromMxl(SAMPLE1_MXL_PATH);
      const generated = [
        "// AUTO-GENERATED by scripts/build.mjs from src/samples/musicxml/sample1.mxl.",
        `export const sampleXml1 = ${JSON.stringify(xml)};`,
        "",
      ].join("\n");
      writeTextIfChanged(SAMPLE1_TS_PATH, generated);
    }
  }

  if (existsSync(toAbs(SAMPLE2_MXL_PATH))) {
    if (!isGeneratedFileCurrent(SAMPLE2_MXL_PATH, SAMPLE2_TS_PATH)) {
      const xml = extractMusicXmlTextFromMxl(SAMPLE2_MXL_PATH);
      const generated = [
        "// AUTO-GENERATED by scripts/build.mjs from src/samples/musicxml/sample2.mxl.",
        `export const sampleXml2 = ${JSON.stringify(xml)};`,
        "",
      ].join("\n");
      writeTextIfChanged(SAMPLE2_TS_PATH, generated);
    }
  }

  if (existsSync(toAbs(SAMPLE3_MXL_PATH))) {
    if (!isGeneratedFileCurrent(SAMPLE3_MXL_PATH, SAMPLE3_TS_PATH)) {
      const xml = extractMusicXmlTextFromMxl(SAMPLE3_MXL_PATH);
      const generated = [
        "// AUTO-GENERATED by scripts/build.mjs from src/samples/musicxml/sample3.mxl.",
        `export const sampleXml3 = ${JSON.stringify(xml)};`,
        "",
      ].join("\n");
      writeTextIfChanged(SAMPLE3_TS_PATH, generated);
    }
  }

  if (existsSync(toAbs(SAMPLE4_MXL_PATH))) {
    if (!isGeneratedFileCurrent(SAMPLE4_MXL_PATH, SAMPLE4_TS_PATH)) {
      const xml = extractMusicXmlTextFromMxl(SAMPLE4_MXL_PATH);
      const generated = [
        "// AUTO-GENERATED by scripts/build.mjs from src/samples/musicxml/sample4.mxl.",
        `export const sampleXml4 = ${JSON.stringify(xml)};`,
        "",
      ].join("\n");
      writeTextIfChanged(SAMPLE4_TS_PATH, generated);
    }
  }

  const definitions = [
    { sourceXml: SAMPLE6_XML_PATH, outTs: SAMPLE6_TS_PATH, exportName: "sampleXml6" },
    { sourceXml: SAMPLE7_XML_PATH, outTs: SAMPLE7_TS_PATH, exportName: "sampleXml7" },
  ];

  for (const def of definitions) {
    if (!existsSync(toAbs(def.sourceXml))) continue;
    if (!isGeneratedFileCurrent(def.sourceXml, def.outTs)) {
      const xml = readText(def.sourceXml).replace(/\r\n/g, "\n");
      const generated = [
        "// AUTO-GENERATED by scripts/build.mjs from src/samples/musicxml/*.musicxml.",
        `export const ${def.exportName} = ${JSON.stringify(xml)};`,
        "",
      ].join("\n");
      writeTextIfChanged(def.outTs, generated);
    }
  }

};

const importRe = /(?:import|export)\s+[^"']*?from\s+["'](.+?)["']|import\s*\(\s*["'](.+?)["']\s*\)/g;

const resolveTsModule = (fromId, specifier) => {
  if (!specifier.startsWith(".")) return null;
  const fromDir = path.dirname(fromId);
  const candidateBase = normalize(path.join(fromDir, specifier));
  const tsFile = `${candidateBase}.ts`;
  const indexTs = `${candidateBase}/index.ts`;
  if (existsSync(toAbs(tsFile))) return tsFile;
  if (existsSync(toAbs(indexTs))) return indexTs;
  throw new Error(`Cannot resolve module: ${specifier} (from ${fromId})`);
};

const collectGraph = () => {
  const queue = [ENTRY_TS];
  const seen = new Set();
  const order = [];

  while (queue.length > 0) {
    const id = queue.pop();
    if (!id || seen.has(id)) continue;
    seen.add(id);
    order.push(id);

    const src = readText(id);
    importRe.lastIndex = 0;
    for (;;) {
      const m = importRe.exec(src);
      if (!m) break;
      const spec = m[1] ?? m[2];
      if (!spec) continue;
      const resolved = resolveTsModule(id, spec);
      if (resolved) queue.push(resolved);
    }
  }

  return order;
};

const compileWithTsc = (tsModules) => {
  mkdirSync(toAbs(TMP_DIR), { recursive: true });

  const args = [
    "--incremental",
    "--tsBuildInfoFile",
    TMP_TSBUILDINFO,
    "--target",
    "ES2018",
    "--module",
    "CommonJS",
    "--lib",
    "DOM,DOM.Iterable,ES2018",
    "--strict",
    "--skipLibCheck",
    "--moduleResolution",
    "node",
    "--outDir",
    TMP_DIR,
    "--rootDir",
    ".",
    ...tsModules,
  ];

  execFileSync("tsc", args, { cwd: ROOT, stdio: "pipe" });
};

const bundle = (tsModules) => {
  const moduleEntries = tsModules
    .map((tsId) => {
      const jsId = tsId.replace(/\.ts$/, ".js");
      const compiled = normalize(path.join(TMP_DIR, jsId));
      const code = readText(compiled);
      return `  ${JSON.stringify(jsId)}: function (require, module, exports) {\n${code}\n  }`;
    })
    .join(",\n");

  return `(function () {\nconst modules = {\n${moduleEntries}\n};\n\nconst cache = {};\n\nfunction normalizePath(p) {\n  const parts = [];\n  for (const part of p.split('/')) {\n    if (!part || part === '.') continue;\n    if (part === '..') {\n      parts.pop();\n    } else {\n      parts.push(part);\n    }\n  }\n  return parts.join('/');\n}\n\nfunction resolve(fromId, specifier) {\n  if (!specifier.startsWith('.')) {\n    throw new Error('External module is not allowed in single-file build: ' + specifier);\n  }\n  const fromParts = fromId.split('/');\n  fromParts.pop();\n  const resolvedBase = normalizePath(fromParts.concat(specifier.split('/')).join('/'));\n  const candidates = [resolvedBase + '.js', resolvedBase + '/index.js'];\n  for (const c of candidates) {\n    if (Object.prototype.hasOwnProperty.call(modules, c)) return c;\n  }\n  throw new Error('Cannot resolve module at runtime: ' + specifier + ' from ' + fromId);\n}\n\nfunction load(id) {\n  if (cache[id]) return cache[id].exports;\n  const factory = modules[id];\n  if (!factory) throw new Error('Unknown module: ' + id);\n  const module = { exports: {} };\n  cache[id] = module;\n  const localRequire = function (specifier) {\n    return load(resolve(id, specifier));\n  };\n  factory(localRequire, module, module.exports);\n  return module.exports;\n}\n\nload(${JSON.stringify(ENTRY_JS)});\n})();\n`;
};

const inlineTemplate = (jsBundle) => {
  const template = readText(TEMPLATE);
  const css = readText(CSS_PATH);
  const verovioJs = readText(VEROVIO_JS_PATH);
  const midiWriterJs = readText(MIDI_WRITER_JS_PATH);
  const uf3pMikuscoreIifeJs = readText(UF3P_MIKUSCORE_IIFE_JS_PATH);
  const hasTokenCssLink = template.includes(`href="${TOKEN_CSS_PATH}"`);
  const hasCoreCssLink = template.includes("href=\"src/css/md3/core-spec.css\"");

  if (!template.includes("href=\"src/css/app.css\"")) {
    throw new Error("Template must include src/css/app.css link tag.");
  }
  if (!template.includes("src=\"src/js/main.js\"")) {
    throw new Error("Template must include src/js/main.js script tag.");
  }
  if (!template.includes("src=\"src/js/verovio.js\"")) {
    throw new Error("Template must include src/js/verovio.js script tag.");
  }
  if (!template.includes("src=\"src/js/midi-writer.js\"")) {
    throw new Error("Template must include src/js/midi-writer.js script tag.");
  }
  if (!template.includes("src=\"src/vendor/utaformatix3/utaformatix3-ts-plus.mikuscore.iife.js\"")) {
    throw new Error("Template must include src/vendor/utaformatix3/utaformatix3-ts-plus.mikuscore.iife.js script tag.");
  }

  const withTokenCss = hasTokenCssLink
    ? template.replace(
        /<link[^>]*href="src\/css\/md3\/token-spec\.css"[^>]*>/,
        `<style>\n${readText(TOKEN_CSS_PATH)}\n</style>`
      )
    : template;

  const withCoreCss = hasCoreCssLink
    ? withTokenCss.replace(
        /<link[^>]*href="src\/css\/md3\/core-spec\.css"[^>]*>/,
        `<style>\n${readText(CORE_CSS_PATH)}\n</style>`
      )
    : withTokenCss;

  const withCss = withCoreCss.replace(
    /<link[^>]*href="src\/css\/app\.css"[^>]*>/,
    `<style>\n${css}\n</style>`
  );

  const withVerovioJs = withCss.replace(
    /<script\s+src="src\/js\/verovio\.js"><\/script>/,
    `<script>\n${verovioJs}\n</script>`
  );

  const withMidiWriterJs = withVerovioJs.replace(
    /<script\s+src="src\/js\/midi-writer\.js"><\/script>/,
    `<script>\n${midiWriterJs}\n</script>`
  );

  const withUf3pMikuscoreIifeJs = withMidiWriterJs.replace(
    /<script\s+src="src\/vendor\/utaformatix3\/utaformatix3-ts-plus\.mikuscore\.iife\.js"><\/script>/,
    `<script>\n${uf3pMikuscoreIifeJs}\n</script>`
  );

  return withUf3pMikuscoreIifeJs.replace(
    /<script\s+src="src\/js\/main\.js"><\/script>/,
    `<script>\n${jsBundle}\n</script>`
  );
};

const run = () => {
  syncBuiltInSamples();
  const tsModules = collectGraph();
  compileWithTsc(tsModules);

  const jsBundle = bundle(tsModules);

  mkdirSync(toAbs("src/js"), { recursive: true });
  writeTextIfChanged(JS_OUT, jsBundle);

  const distHtml = inlineTemplate(jsBundle);
  writeTextIfChanged(DIST, distHtml);

  process.stdout.write(`Built ${DIST} and ${JS_OUT}\n`);
};

run();
